// ── Server API helpers (per-session architecture) ──
async function apiGet(path) { try { const r = await fetch(path); return r.ok ? await r.json() : null; } catch { return null; } }
async function apiPost(path, body) { try { const r = await fetch(path, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(body) }); return { ok: r.ok, status: r.status, data: await r.json().catch(() => ({})) }; } catch { return { ok: false, status: 0, data: {} }; } }
async function apiPut(path, body) { try { const r = await fetch(path, { method: "PUT", headers: { "Content-Type": "application/json" }, body: JSON.stringify(body) }); return { ok: r.ok, data: await r.json().catch(() => ({})) }; } catch { return { ok: false, data: {} }; } }
async function apiDelete(path) { try { const r = await fetch(path, { method: "DELETE" }); return r.ok; } catch { return false; } }
async function fetchKeyStatus() { try { const r = await fetch("/api/keys"); if (!r.ok) return { anthropic: false, xai: false, openai: false, deepseek: false, zai: false, google: false, customEndpoints: [] }; return await r.json(); } catch { return { anthropic: false, xai: false, openai: false, deepseek: false, zai: false, google: false, customEndpoints: [] }; } }


// ═══════════════════════════════════════════════════════════
// MARKDOWN
// ═══════════════════════════════════════════════════════════

function renderMarkdown(text) {
  if (!text) return "";
  const cbs = [];
  let p = text.replace(/```(\w*)\n([\s\S]*?)```/g, (_, l, c) => { const i = cbs.length; cbs.push({ l, c: c.replace(/\n$/, ""), ok: true }); return `%%CB_${i}%%`; });
  p = p.replace(/```(\w*)(?:\n([\s\S]*))?$/g, (m, l, c) => { const i = cbs.length; cbs.push({ l, c: c || "", ok: false }); return `%%CB_${i}%%`; });
  const esc = s => s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
  const safeUrl = u => /^(https?:\/\/|mailto:)/i.test(u) ? u : "";
  const inl = s => s.replace(/`([^`]+)`/g, '<code class="ic">$1</code>').replace(/\*\*\*(.+?)\*\*\*/g, "<strong><em>$1</em></strong>").replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>").replace(/\*(.+?)\*/g, "<em>$1</em>").replace(/\[([^\]]+)\]\(([^)]+)\)/g, (_, t, u) => `<a href="${safeUrl(u)}" target="_blank" rel="noopener">${t}</a>`).replace(/\u201c(.*?)\u201d/g, "<span class='dlg'>\u201c$1\u201d</span>").replace(/"(.*?)"/g, '<span class="dlg">"$1"</span>');
  const lines = p.split("\n"); let html = "", inList = false, lt = null;
  for (let i = 0; i < lines.length; i++) {
    let ln = lines[i]; const cbM = ln.match(/^%%CB_(\d+)%%$/);
    if (cbM) { if (inList) { html += lt === "ul" ? "</ul>" : "</ol>"; inList = false; } const cb = cbs[+cbM[1]]; html += `<div class="cb-wrap"><div class="cb-header"><span>${esc(cb.l || "text")}${cb.ok ? "" : " ···"}</span><button class="cb-copy">Copy</button></div><pre><code>${esc(cb.c)}</code></pre></div>`; continue; }
    if (/^#{1,6}\s/.test(ln)) { if (inList) { html += lt === "ul" ? "</ul>" : "</ol>"; inList = false; } const lv = ln.match(/^(#+)/)[1].length; html += `<h${lv}>${inl(esc(ln.replace(/^#+\s*/, "")))}</h${lv}>`; continue; }
    if (/^>\s/.test(ln)) { if (inList) { html += lt === "ul" ? "</ul>" : "</ol>"; inList = false; } let bq = inl(esc(ln.replace(/^>\s*/, ""))); while (i + 1 < lines.length && /^>\s/.test(lines[i + 1])) { i++; bq += "<br>" + inl(esc(lines[i].replace(/^>\s*/, ""))); } html += `<blockquote>${bq}</blockquote>`; continue; }
    if (/^---+$/.test(ln.trim())) { if (inList) { html += lt === "ul" ? "</ul>" : "</ol>"; inList = false; } html += "<hr>"; continue; }
    const ulM = ln.match(/^(\s*)[-*]\s+(.*)/), olM = ln.match(/^(\s*)\d+\.\s+(.*)/);
    if (ulM) { if (!inList || lt !== "ul") { if (inList) html += lt === "ul" ? "</ul>" : "</ol>"; html += "<ul>"; inList = true; lt = "ul"; } html += `<li>${inl(esc(ulM[2]))}</li>`; continue; }
    if (olM) { if (!inList || lt !== "ol") { if (inList) html += lt === "ul" ? "</ul>" : "</ol>"; html += "<ol>"; inList = true; lt = "ol"; } html += `<li>${inl(esc(olM[2]))}</li>`; continue; }
    if (inList) { html += lt === "ul" ? "</ul>" : "</ol>"; inList = false; }
    if (ln.trim() === "") html += "<br>"; else html += `<p>${inl(esc(ln))}</p>`;
  }
  if (inList) html += lt === "ul" ? "</ul>" : "</ol>";
  return html;
}

// ═══════════════════════════════════════════════════════════
// COST / EXPORT / HELPERS
// ═══════════════════════════════════════════════════════════

function calcCost(mid, u, ttl = "5m") { const pr = PRICING[mid] || { input: 0, output: 0 }; const cr = u.cacheRead || 0, cw = u.cacheCreation || 0; let c = (u.input || 0) / 1e6 * pr.input + (u.output || 0) / 1e6 * pr.output; if (pr.cacheRead) c += cr / 1e6 * pr.cacheRead; if (pr.cacheWrite5m) c += cw / 1e6 * (ttl === "1h" ? (pr.cacheWrite1h || pr.cacheWrite5m) : pr.cacheWrite5m); return c; }
function sessionTotals(s) { let inp = 0, out = 0, cr = 0, cw = 0; for (const m of s.messages) { if (m.usage) { inp += m.usage.input || 0; out += m.usage.output || 0; cr += m.usage.cacheRead || 0; cw += m.usage.cacheCreation || 0; } } return { input: inp, output: out, cacheRead: cr, cacheCreation: cw, totalTokens: inp + out, cost: s.messages.reduce((a, m) => a + (m.usage ? calcCost(m.model || s.selectedModel, m.usage, s.cacheTTL || "5m") : 0), 0) }; }
function lastInputTokens(s) { for (let i = s.messages.length - 1; i >= 0; i--) { const u = s.messages[i].usage; if (u?.input) return (u.input || 0) + (u.cacheRead || 0) + (u.cacheCreation || 0); } return 0; }
function exportSession(s) { let md = `# ${s.name}\n\n`; for (const m of s.messages) { if (m.role === "cold-start") { md += `### Cold Start\n\n${m.content}\n\n`; continue; } if (META_PREFIXES.some(p => m.content?.startsWith(p))) continue; const clean = (m.content || "").replace(/\n\n\*\[Stopped\]\*$/, "").replace(/\n\n---\n\n\*\[Stream interrupted:.*?\]\*$/, ""); if (!clean.trim()) continue; md += `### ${m.role === "user" ? "User" : "Assistant"}\n\n${clean}\n\n`; } const b = new Blob([md], { type: "text/markdown" }); const u = URL.createObjectURL(b); const a = document.createElement("a"); a.href = u; a.download = `${s.name.replace(/[^a-zA-Z0-9]/g, "_")}_${new Date().toISOString().slice(0, 10)}.md`; a.click(); URL.revokeObjectURL(u); }

const META_PREFIXES = ["**Credit Balance Error:**", "**API Error:**", "**Network Error:**", "**Authentication Error:**", "*[Stopped before response began]*", "*[Response contained only thinking"];

// ═══════════════════════════════════════════════════════════
// STREAM PARSERS
// ═══════════════════════════════════════════════════════════

function parseAnthropicEvent(evt, st) {
  if (evt.type === "error") { st.error = evt.error?.message || "Anthropic API error"; return {}; }
  if (evt.type === "message_start" && evt.message?.usage) { st.usage.input = evt.message.usage.input_tokens || 0; st.usage.cacheRead = evt.message.usage.cache_read_input_tokens || 0; st.usage.cacheCreation = evt.message.usage.cache_creation_input_tokens || 0; return { u: true }; }
  if (evt.type === "content_block_start") st.blockType = evt.content_block?.type || "text";
  if (evt.type === "content_block_delta") { if (evt.delta?.type === "thinking_delta" || st.blockType === "thinking") { st.thinking += (evt.delta?.thinking || ""); return { th: true }; } if (evt.delta?.type === "text_delta" || evt.delta?.text !== undefined) { st.text += (evt.delta?.text || ""); return { tx: true }; } }
  if (evt.type === "content_block_stop") st.blockType = null;
  if (evt.type === "message_delta") { if (evt.usage) st.usage.output = evt.usage.output_tokens || 0; if (evt.delta?.stop_reason) st.stopReason = evt.delta.stop_reason; return { u: true }; }
  return {};
}
function parseXaiEvent(evt, st) {
  if (evt.choices?.[0]?.finish_reason) st.stopReason = evt.choices[0].finish_reason === "length" ? "max_tokens" : evt.choices[0].finish_reason;
  if (evt.choices?.[0]?.delta?.content) { st.text += evt.choices[0].delta.content; return { tx: true }; }
  if (evt.choices?.[0]?.delta?.reasoning_content) { st.thinking += evt.choices[0].delta.reasoning_content; return { th: true }; }
  if (evt.choices?.[0]?.delta?.reasoning?.content) { st.thinking += evt.choices[0].delta.reasoning.content; return { th: true }; }
  if (evt.usage) { st.usage.input = evt.usage.prompt_tokens || 0; st.usage.output = evt.usage.completion_tokens || 0; return { u: true }; }
  return {};
}

// OpenAI Responses API uses named SSE events — parser receives {event, data}
function parseOpenaiResponsesEvent(eventName, data, st) {
  if (eventName === "response.reasoning_summary_text.delta" || eventName === "response.reasoning_text.delta") { st.thinking += data.delta || ""; return { th: true }; }
  if (eventName === "response.output_text.delta") { st.text += data.delta || ""; return { tx: true }; }
  if (eventName === "response.completed" || eventName === "response.done") {
    const u = data.response?.usage || data.usage;
    if (u) { st.usage.input = u.input_tokens || 0; st.usage.output = u.output_tokens || 0; }
    return { u: true };
  }
  if (eventName === "response.incomplete") { st.stopReason = "max_tokens"; return {}; }
  if (eventName === "response.failed") { st.error = data.response?.error?.message || data.error?.message || "Unknown error"; return {}; }
  return {};
}

// Google Gemini — data-only SSE with candidates[].content.parts[], thinking parts have thought:true
function parseGeminiEvent(evt, st) {
  let r = {};
  const c = evt.candidates?.[0];
  if (c?.finishReason) st.stopReason = c.finishReason === "MAX_TOKENS" ? "max_tokens" : c.finishReason;
  if (c?.content?.parts) { for (const p of c.content.parts) { if (p.thought && p.text) { st.thinking += p.text; r.th = true; } else if (p.text) { st.text += p.text; r.tx = true; } } }
  if (evt.usageMetadata) { st.usage.input = evt.usageMetadata.promptTokenCount || 0; st.usage.output = evt.usageMetadata.candidatesTokenCount || 0; r.u = true; }
  return r;
}

// ═══════════════════════════════════════════════════════════
// FILE READING
// ═══════════════════════════════════════════════════════════

const TEXT_EXTS = [".md", ".txt", ".csv", ".json", ".xml", ".yaml", ".yml", ".log", ".js", ".py", ".html", ".css"];
const IMAGE_EXTS = [".png", ".jpg", ".jpeg", ".gif", ".webp"];

function readFileAsText(file) { return new Promise((res, rej) => { const r = new FileReader(); r.onload = () => res(r.result); r.onerror = rej; r.readAsText(file); }); }
function readFileAsBase64(file) { return new Promise((res, rej) => { const r = new FileReader(); r.onload = () => res(r.result.split(",")[1]); r.onerror = rej; r.readAsDataURL(file); }); }

async function processFile(file) {
  const ext = "." + file.name.split(".").pop().toLowerCase();
  if (TEXT_EXTS.includes(ext)) { const content = await readFileAsText(file); return { name: file.name, kind: "text", content, size: file.size }; }
  if (IMAGE_EXTS.includes(ext)) { const mimeMap = { ".png": "image/png", ".jpg": "image/jpeg", ".jpeg": "image/jpeg", ".gif": "image/gif", ".webp": "image/webp" }; const data = await readFileAsBase64(file); return { name: file.name, kind: "image", mimeType: file.type || mimeMap[ext] || "image/png", data, size: file.size }; }
  if (ext === ".pdf") { const data = await readFileAsBase64(file); return { name: file.name, kind: "pdf", data, size: file.size }; }
  // Fallback: try as text
  try { const content = await readFileAsText(file); return { name: file.name, kind: "text", content, size: file.size }; } catch { return null; }
}

// ═══════════════════════════════════════════════════════════
// COMPONENTS
// ═══════════════════════════════════════════════════════════

function ThinkingBlock({ text, streaming }) {
  const [open, setOpen] = useState(false);
  if (!text) return null;
  return (<div className="thinking-block"><button className="thinking-toggle" onClick={() => setOpen(!open)}><Brain size={13} /><span>Thinking{streaming ? "..." : ""}</span>{open ? <ChevronDown size={12} /> : <ChevronRight size={12} />}{!streaming && <span className="thinking-len">{text.length > 500 ? `${(text.length / 1000).toFixed(1)}K` : `${text.length} chars`}</span>}</button>{open && <div className="thinking-content">{text}</div>}</div>);
}

function useDebouncedEffect(fn, deps, delay) { useEffect(() => { const t = setTimeout(fn, delay); return () => clearTimeout(t); }, deps); }

function FileChips({ files, onRemove }) {
  if (!files?.length) return null;
  return (<div className="file-chips">{files.map((f, i) => (
    <span key={i} className={`file-chip ${f.kind}`}>
      <span className="file-chip-icon">{f.kind === "text" ? "📄" : f.kind === "image" ? "🖼" : "📑"}</span>
      <span className="file-chip-name">{f.name}</span>
      {f.size && <span className="file-chip-size">{f.size > 1024 * 1024 ? `${(f.size / 1024 / 1024).toFixed(1)}MB` : `${(f.size / 1024).toFixed(0)}KB`}</span>}
      {onRemove && <button className="file-chip-x" onClick={(e) => { e.stopPropagation(); onRemove(i); }}>×</button>}
    </span>
  ))}</div>);
}

