      const fetchHeaders = { "Content-Type": "application/json", "X-Session-Id": curId, "X-Model-Id": modelId, "X-Msg-Count": String(newMsgs.length) };
      if (isCustom && mi.customEndpointId) fetchHeaders["X-Custom-Endpoint-Id"] = mi.customEndpointId;

      const resp = await fetch(proxyUrl, { method: "POST", signal: controller.signal, cache: "no-store", headers: fetchHeaders, body: JSON.stringify(reqBody) });

      if (!resp.ok) { const err = await resp.json().catch(() => ({ error: { message: resp.statusText } })); const msg = err.error?.message || (typeof err.error === "string" ? err.error : null) || err.message || `API error ${resp.status}`; if (resp.status === 401 || resp.status === 403) throw Object.assign(new Error(msg), { isAuth: true }); if (typeof msg === "string" && msg.toLowerCase().includes("credit balance")) throw Object.assign(new Error(msg), { isCredit: true }); throw new Error(msg); }

