      const aMsg = { role: "assistant", content: data.revisedPrompt ? `*Revised prompt: ${data.revisedPrompt}*` : "", model: igModel, generatedImage: data.imageId, usage: data.usage || null };
      setSessions(p => { const s = p[curId]; if (!s) return p; return { ...p, [curId]: { ...s, messages: [...(s.messages || []), aMsg] } }; });
