  const totals = active?.messages ? sessionTotals(active) : { input: 0, output: 0, cacheRead: 0, cacheCreation: 0, totalTokens: 0, cost: 0 };
  const ctxTok = active?.messages ? (isActiveStreaming && streamUsage ? (streamUsage.input || 0) + (streamUsage.cacheRead || 0) + (streamUsage.cacheCreation || 0) : lastInputTokens(active)) : 0;
  const ctxMax = selMI?.ctx || 200000;
